-- ============================================================
-- data-engineer-roadmap-sh-full-detailed-seed-v1.sql
-- Full detailed Data Engineer roadmap seed based on roadmap.sh/data-engineer.
-- Idempotent seed: safe to rerun in the same database/session.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Data Engineer Roadmap', 'Data Engineer Roadmap - roadmap.sh Full Detailed Seed', 'Data Engineering Roadmap Full Detailed Seed')
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Data Engineer Roadmap', 'Data Engineer Roadmap - roadmap.sh Full Detailed Seed', 'Data Engineering Roadmap Full Detailed Seed')
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Data Engineer Roadmap', 'Data Engineer Roadmap - roadmap.sh Full Detailed Seed', 'Data Engineering Roadmap Full Detailed Seed')
);

DELETE FROM public.roadmap
WHERE title IN ('Data Engineer Roadmap', 'Data Engineer Roadmap - roadmap.sh Full Detailed Seed', 'Data Engineering Roadmap Full Detailed Seed');

INSERT INTO public.career_role (name, slug, description, category, is_active)
VALUES (
    'Data Engineer',
    'data-engineer',
    'Data engineer path covering SQL, Python, data modeling, warehouses, lakes, batch pipelines, streaming, orchestration, cloud platforms, governance, quality, DevOps, observability, and production data platform design.',
    'Data',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'data-engineer'
), inserted_roadmap AS (
    INSERT INTO public.roadmap (career_role_id, title, description, roadmap_type, source_type, visibility)
    SELECT
        career_role_id,
        'Data Engineer Roadmap',
        'A structured learning path for becoming a data engineer, covering SQL, Python, data modeling, warehouses, data lakes, batch processing, streaming, orchestration, cloud platforms, data quality, governance, DevOps, observability, and production-ready data platform design.',
        'template',
        'static',
        'public'
    FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    INSERT INTO public.roadmap_version
    (roadmap_id, version_number, status, title, description, estimated_total_hours, generation_status, generation_context, layout_direction, layout_algorithm, published_at)
    SELECT
        roadmap_id,
        1,
        'published',
        'Data Engineer Roadmap v1',
        'A practical data engineering roadmap that moves from foundations to production readiness through phases, guided topics, checkpoints, optional practice projects, and required milestone projects.',
        460,
        'none',
        '{"source":"roadmap.sh/data-engineer","version":"v1","projectPolicy":"mini projects are optional; milestone projects are required","estimatedHoursBasis":"representative required path, not every optional branch"}'::jsonb,
        'TB',
        'manual',
        now()
    FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;

